// 1-2 day implementation: drop into tools/annotate_corpus_invariants.py, no new file needed.

MAX_REFINE_ROUNDS = 2  # initial + 2 re-extracts = K=3 candidates max

def extract_and_validate_v3(finding, client, model):
    history = []  # [(inv, critic_verdict)]
    inv = extract_invariant(finding, client, model)
    history.append((inv, None))
    for round_idx in range(MAX_REFINE_ROUNDS + 1):
        verdict = validate_extraction(finding, inv, client, model)
        history[-1] = (inv, verdict)
        if not verdict['refuted']:
            return {**inv, 'validation': verdict, 'rounds': round_idx, 'history': history}
        if round_idx == MAX_REFINE_ROUNDS:
            break
        # CRITIC IS THE GRADIENT: feed verdict.reason back as additional context
        inv = re_extract_with_critic(finding, inv, verdict['reason'], client, model)
        history.append((inv, None))
    return {**inv, 'validation': verdict, 'rounds': MAX_REFINE_ROUNDS + 1, 'history': history}

// Pre-registered metric for H13 in arXiv Section 7:
//
// H13 (CEGAR-lite multiplies multi-mode): On the calibration corpus N=50, the
// CLEAN-rate of {Pass A v2 multi-mode + K=3 critic-feedback re-extract} is
// strictly greater than {Pass A v2 multi-mode + K=1}, AND the lift is at least
// 2x the lift from v1->v2 alone.
//
// Operational: measure three conditions on the SAME 50 findings:
//   C0: v1 single-mode + K=1     (baseline = 7/50 = 14%)
//   C1: v2 multi-mode + K=1      (additivity test)
//   C2: v2 multi-mode + K=3      (multiplicativity test)
// Pre-registered prediction: CLEAN(C2) - CLEAN(C1) >= 2 * (CLEAN(C1) - CLEAN(C0)).
// If the inequality fails, H13 is falsified — modes and CEGAR are merely additive,
// not multiplicative, and the architectural framing in Section 4 needs revision.

